  ins.run('x', 'X', 'tc2', 0.0004, 1000);
  ins.run('y', 'Y', 'tc2', 0.0008, 2000);
  ins.run('z', 'Z', 'tc2', 0.0012, 3000);

  renormalizeColumn('tc2');

